'use strict';

var i18n = require('./i18n-W_b7n6on.js');
var coreContext = require('@nordic/core-context');
require('react/jsx-runtime');
require('@meli/i18n');
require('react');

/**
 * Provides an instance of the `I18n` class anywhere after `createNordicI18nMiddlewares` has run, including React Components.
 *
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#geti18n-getter | Documentation}
 *
 * @example
 *
 * import { getI18n } from 'nordic/i18n';
 *
 * const SomeComponent = () => {
 *   const i18n = getI18n();
 *
 *   return (
 *     <div>
 *       <p>{i18n.gettext('Some text')}</p>
 *       <p>Other text</p>
 *     </div>
 *   );
 * };
 */
function getI18n() {
  const i18n = coreContext.getI18n();
  return i18n;
}

exports.I18n = i18n.I18n;
exports.getI18n = getI18n;
